     1→/**
     2→ * MMS Ingestion Service
     3→ *
     4→ * Processes daily CSV files containing mileage data.
     5→ * Validates records, handles meter events, and updates the database.
     6→ *
     7→ * Data flow:
     8→ * 1. CSV file arrives via file watcher or API upload
     9→ * 2. File is validated (format, size, structure)
    10→ * 3. Records are parsed and validated in batches
    11→ * 4. Anomalies are detected (NEGATIVE, SPIKE, DUPLICATE)
    12→ * 5. Mileage readings are inserted/updated
    13→ * 6. Train current_mileage_km is updated
    14→ * 7. Fleet mileage targets are recalculated
    15→ *
    16→ * Business rules:
    17→ * - Max file size: 10MB
    18→ * - Expected file pattern: mileage_YYYYMMDD.csv
    19→ * - Batch size: 100 records per transaction
    20→ * - Anomaly thresholds: NEGATIVE < 0, SPIKE > 1000 km/day
    21→ * - Meter adjustments are applied to maintain mileage continuity
    22→ *
    23→ * @see specs/004-domain-services.md Section 4.2
    24→ */
    25→
    26→import { eq, and, desc, lte, sql } from 'drizzle-orm';
    27→import * as Papa from 'papaparse';
    28→import * as fs from 'node:fs';
    29→import * as path from 'node:path';
    30→import { BaseService, MmsAttributes } from '../lib/services/base';
    31→import { trains, mileageReadings, meterEvents } from '../lib/db/schema';
    32→import {
    33→  ValidationError,
    34→  FileError,
    35→  BusinessRuleError,
    36→} from '../lib/errors';
    37→import { mileageCsvRowSchema } from '../lib/schemas';
    38→import { addJob, QUEUE_NAMES, type IngestionJobData } from '../lib/queue';
    39→import { ingestionMetrics, recordIngestionComplete, recordIngestionAnomaly } from '../lib/metrics';
    40→
    41→// =============================================================================
    42→// Constants
    43→// =============================================================================
    44→
    45→const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
    46→const EXPECTED_FILE_PATTERN = /^mileage_\d{8}\.csv$/;
    47→const BATCH_SIZE = 100;
    48→const SPIKE_THRESHOLD_KM = 1000;
    49→const ALERT_THRESHOLD_HOURS = 2;
    50→
    51→// =============================================================================
    52→// Types
    53→// =============================================================================
    54→
    55→/** Anomaly types detected during ingestion */
    56→export type AnomalyType = 'NEGATIVE' | 'SPIKE' | 'DUPLICATE' | 'MISSING' | 'FUTURE_DATE' | 'UNKNOWN_TRAIN';
    57→
    58→/** A detected anomaly in the mileage data */
    59→export interface AnomalyRecord {
    60→  trainNumber: string;
    61→  readingDate: string;
    62→  type: AnomalyType;
    63→  value: number | null;
    64→  message: string;
    65→  rawReading?: number;
    66→  previousReading?: number;
    67→}
    68→
    69→/** Result of meter event detection */
    70→export interface MeterEventRecord {
    71→  trainNumber: string;
    72→  trainId: string;
    73→  eventDate: string;
    74→  eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP';
    75→  oldReading: number;
    76→  newReading: number;
    77→  adjustmentKm: number;
    78→}
    79→
    80→/** Configuration for the file watcher */
    81→export interface FileWatcherConfig {
    82→  inboxPath: string;
    83→  processedPath: string;
    84→  quarantinePath: string;
    85→  expectedFilePattern?: RegExp;
    86→  maxFileSizeBytes?: number;
    87→  alertThresholdHours?: number;
    88→  pollIntervalMs?: number;
    89→}
    90→
    91→/** Result of file validation */
    92→export interface FileValidationResult {
    93→  valid: boolean;
    94→  errors: string[];
    95→  warnings: string[];
    96→  fileSize: number;
    97→  rowCount?: number;
    98→}
    99→
   100→/** Result of ingestion processing */
   101→export interface IngestionResult {
   102→  jobId: string;
   103→  fileName: string;
   104→  totalRecords: number;
   105→  validRecords: number;
   106→  invalidRecords: number;
   107→  anomalies: AnomalyRecord[];
   108→  meterEvents: MeterEventRecord[];
   109→  processingTimeMs: number;
   110→  trainsUpdated: number;
   111→  status: 'SUCCESS' | 'PARTIAL' | 'FAILED';
   112→  errorMessage?: string;
   113→}
   114→
   115→/** Internal record type after parsing */
   116→interface ParsedMileageRecord {
   117→  trainNumber: string;
   118→  readingDate: string;
   119→  odometerKm: number;
   120→  rowIndex: number;
   121→}
   122→
   123→/** Row validation result */
   124→interface RowValidationResult {
   125→  valid: boolean;
   126→  record?: ParsedMileageRecord;
   127→  error?: string;
   128→  anomaly?: AnomalyRecord;
   129→}
   130→
   131→// =============================================================================
   132→// Ingestion Service
   133→// =============================================================================
   134→
   135→export class IngestionService extends BaseService {
   136→  private lastFileReceivedAt: Date | null = null;
   137→
   138→  constructor() {
   139→    super({ name: 'ingestion-service', version: '1.0.0' });
   140→  }
   141→
   142→  // ===========================================================================
   143→  // File Validation
   144→  // ===========================================================================
   145→
   146→  /**
   147→   * Validate a mileage CSV file before processing
   148→   *
   149→   * Checks:
   150→   * - File exists and is readable
   151→   * - File size within limit
   152→   * - Filename matches expected pattern
   153→   * - CSV structure is valid
   154→   * - Required columns present
   155→   */
   156→  async validateFile(filePath: string): Promise<FileValidationResult> {
   157→    return this.traced('validateFile', async (span) => {
   158→      span.setAttribute('file.path', filePath);
   159→
   160→      const errors: string[] = [];
   161→      const warnings: string[] = [];
   162→      const fileName = path.basename(filePath);
   163→
   164→      // Check file exists
   165→      if (!fs.existsSync(filePath)) {
   166→        return {
   167→          valid: false,
   168→          errors: [`File not found: ${filePath}`],
   169→          warnings: [],
   170→          fileSize: 0,
   171→        };
   172→      }
   173→
   174→      // Check file size
   175→      const stats = fs.statSync(filePath);
   176→      const fileSize = stats.size;
   177→      span.setAttribute('file.size', fileSize);
   178→
   179→      if (fileSize === 0) {
   180→        errors.push('File is empty');
   181→      }
   182→
   183→      if (fileSize > MAX_FILE_SIZE_BYTES) {
   184→        errors.push(`File size ${fileSize} exceeds maximum ${MAX_FILE_SIZE_BYTES} bytes`);
   185→      }
   186→
   187→      // Check filename pattern
   188→      if (!EXPECTED_FILE_PATTERN.test(fileName)) {
   189→        warnings.push(`Filename '${fileName}' does not match expected pattern mileage_YYYYMMDD.csv`);
   190→      }
   191→
   192→      // Validate CSV structure (read first 10 lines)
   193→      if (fileSize > 0) {
   194→        try {
   195→          const sample = this.readFirstLines(filePath, 10);
   196→          const structureErrors = this.validateCsvStructure(sample);
   197→          errors.push(...structureErrors);
   198→        } catch (error) {
   199→          errors.push(`Failed to read CSV: ${error instanceof Error ? error.message : 'Unknown error'}`);
   200→        }
   201→      }
   202→
   203→      const valid = errors.length === 0;
   204→      span.setAttribute('validation.valid', valid);
   205→      span.setAttribute('validation.errorCount', errors.length);
   206→
   207→      return {
   208→        valid,
   209→        errors,
   210→        warnings,
   211→        fileSize,
   212→      };
   213→    });
   214→  }
   215→
   216→  /**
   217→   * Read first N lines from a file
   218→   */
   219→  private readFirstLines(filePath: string, lineCount: number): string {
   220→    const content = fs.readFileSync(filePath, 'utf-8');
   221→    const lines = content.split('\n').slice(0, lineCount);
   222→    return lines.join('\n');
   223→  }
   224→
   225→  /**
   226→   * Validate CSV structure (headers and format)
   227→   */
   228→  private validateCsvStructure(csvSample: string): string[] {
   229→    const errors: string[] = [];
   230→
   231→    const parseResult = Papa.parse(csvSample, {
   232→      header: true,
   233→      skipEmptyLines: true,
   234→    });
   235→
   236→    if (parseResult.errors.length > 0) {
   237→      for (const error of parseResult.errors.slice(0, 5)) {
   238→        errors.push(`CSV parse error at row ${error.row ?? 'unknown'}: ${error.message}`);
   239→      }
   240→      return errors;
   241→    }
   242→
   243→    // Check required columns
   244→    const headers = parseResult.meta.fields ?? [];
   245→    const requiredColumns = ['train_number', 'reading_date', 'odometer_km'];
   246→
   247→    for (const col of requiredColumns) {
   248→      if (!headers.includes(col)) {
   249→        errors.push(`Missing required column: ${col}`);
   250→      }
   251→    }
   252→
   253→    return errors;
   254→  }
   255→
   256→  // ===========================================================================
   257→  // File Processing
   258→  // ===========================================================================
   259→
   260→  /**
   261→   * Queue a file for async processing
   262→   */
   263→  async queueFileForProcessing(
   264→    filePath: string,
   265→    uploadedBy?: string
   266→  ): Promise<{ jobId: string }> {
   267→    return this.traced('queueFileForProcessing', async (span) => {
   268→      span.setAttribute('file.path', filePath);
   269→
   270→      // Validate file first
   271→      const validation = await this.validateFile(filePath);
   272→
   273→      if (!validation.valid) {
   274→        throw new ValidationError('File validation failed', {
   275→          field: 'file',
   276→          context: {
   277→            errors: validation.errors,
   278→            warnings: validation.warnings,
   279→          },
   280→        });
   281→      }
   282→
   283→      const fileName = path.basename(filePath);
   284→      const jobData: IngestionJobData = {
   285→        filePath,
   286→        fileName,
   287→        fileSize: validation.fileSize,
   288→        uploadedBy,
   289→      };
   290→
   291→      const { id } = await addJob(
   292→        QUEUE_NAMES.INGESTION,
   293→        'process-mileage-csv',
   294→        jobData,
   295→        {
   296→          attempts: 3,
   297→          backoff: { type: 'exponential', delay: 5000 },
   298→        }
   299→      );
   300→
   301→      this.lastFileReceivedAt = new Date();
   302→
   303→      this.log.info(
   304→        { jobId: id, fileName, fileSize: validation.fileSize, uploadedBy },
   305→        'File queued for ingestion'
   306→      );
   307→
   308→      return { jobId: id };
   309→    });
   310→  }
   311→
   312→  /**
   313→   * Process a mileage CSV file (main ingestion entry point)
   314→   *
   315→   * This is the core method called by the ingestion worker.
   316→   */
   317→  async processFile(
   318→    filePath: string,
   319→    jobId: string = crypto.randomUUID()
   320→  ): Promise<IngestionResult> {
   321→    return this.traced('processFile', async (span) => {
   322→      const startTime = Date.now();
   323→      const fileName = path.basename(filePath);
   324→
   325→      span.setAttribute(MmsAttributes.INGESTION_FILE, fileName);
   326→      span.setAttribute(MmsAttributes.INGESTION_JOB_ID, jobId);
   327→
   328→      ingestionMetrics.filesReceived.inc();
   329→
   330→      const result: IngestionResult = {
   331→        jobId,
   332→        fileName,
   333→        totalRecords: 0,
   334→        validRecords: 0,
   335→        invalidRecords: 0,
   336→        anomalies: [],
   337→        meterEvents: [],
   338→        processingTimeMs: 0,
   339→        trainsUpdated: 0,
   340→        status: 'SUCCESS',
   341→      };
   342→
   343→      try {
   344→        // Parse CSV
   345→        const records = await this.parseCsv(filePath);
   346→        result.totalRecords = records.length;
   347→        span.setAttribute(MmsAttributes.INGESTION_RECORD_COUNT, records.length);
   348→
   349→        ingestionMetrics.recordsProcessed.inc(records.length);
   350→
   351→        if (records.length === 0) {
   352→          result.status = 'PARTIAL';
   353→          result.errorMessage = 'No valid records found in CSV';
   354→          this.log.warn({ fileName, jobId }, 'CSV file contains no valid records');
   355→          return result;
   356→        }
   357→
   358→        // Process in batches
   359→        const batches = this.chunk(records, BATCH_SIZE);
   360→        const trainIdsUpdated = new Set<string>();
   361→
   362→        for (const batch of batches) {
   363→          const batchResult = await this.processBatch(batch, fileName, result);
   364→          for (const trainId of batchResult.trainIdsUpdated) {
   365→            trainIdsUpdated.add(trainId);
   366→          }
   367→        }
   368→
   369→        result.trainsUpdated = trainIdsUpdated.size;
   370→
   371→        // Update train current mileage for all affected trains
   372→        await this.updateTrainMileage(records, trainIdsUpdated);
   373→
   374→        // Determine final status
   375→        if (result.invalidRecords > 0 && result.validRecords > 0) {
   376→          result.status = 'PARTIAL';
   377→        } else if (result.validRecords === 0) {
   378→          result.status = 'FAILED';
   379→          result.errorMessage = 'All records failed validation';
   380→        }
   381→
   382→        result.processingTimeMs = Date.now() - startTime;
   383→
   384→        span.setAttribute('result.validRecords', result.validRecords);
   385→        span.setAttribute('result.invalidRecords', result.invalidRecords);
   386→        span.setAttribute('result.anomalyCount', result.anomalies.length);
   387→        span.setAttribute('result.status', result.status);
   388→
   389→        recordIngestionComplete(result.status, result.processingTimeMs);
   390→
   391→        this.log.info(
   392→          {
   393→            jobId,
   394→            fileName,
   395→            totalRecords: result.totalRecords,
   396→            validRecords: result.validRecords,
   397→            invalidRecords: result.invalidRecords,
   398→            anomalies: result.anomalies.length,
   399→            trainsUpdated: result.trainsUpdated,
   400→            processingTimeMs: result.processingTimeMs,
   401→            status: result.status,
   402→          },
   403→          `Ingestion complete: ${result.validRecords}/${result.totalRecords} records processed`
   404→        );
   405→
   406→        return result;
   407→      } catch (error) {
   408→        result.processingTimeMs = Date.now() - startTime;
   409→        result.status = 'FAILED';
   410→        result.errorMessage = error instanceof Error ? error.message : 'Unknown error';
   411→
   412→        recordIngestionComplete('FAILED', result.processingTimeMs);
   413→
   414→        this.log.error(
   415→          { error, jobId, fileName },
   416→          `Ingestion failed: ${result.errorMessage}`
   417→        );
   418→
   419→        throw error;
   420→      }
   421→    });
   422→  }
   423→
   424→  /**
   425→   * Parse a CSV file and validate each row
   426→   */
   427→  private async parseCsv(filePath: string): Promise<ParsedMileageRecord[]> {
   428→    return this.traced('parseCsv', async (span) => {
   429→      span.setAttribute('file.path', filePath);
   430→
   431→      const content = fs.readFileSync(filePath, 'utf-8');
   432→
   433→      return new Promise<ParsedMileageRecord[]>((resolve, reject) => {
   434→        const records: ParsedMileageRecord[] = [];
   435→        let rowIndex = 0;
   436→
   437→        Papa.parse(content, {
   438→          header: true,
   439→          skipEmptyLines: true,
   440→          complete: (results) => {
   441→            span.setAttribute('parse.rowCount', results.data.length);
   442→
   443→            for (const row of results.data) {
   444→              rowIndex++;
   445→              const validation = this.validateRow(row, rowIndex);
   446→
   447→              if (validation.valid && validation.record) {
   448→                records.push(validation.record);
   449→              }
   450→            }
   451→
   452→            this.log.debug(
   453→              { filePath, totalRows: results.data.length, validRows: records.length },
   454→              'CSV parsing complete'
   455→            );
   456→
   457→            resolve(records);
   458→          },
   459→          error: (error: Error) => {
   460→            reject(new FileError(`CSV parse error: ${error.message}`, {
   461→              filePath,
   462→              operation: 'parse',
   463→            }));
   464→          },
   465→        });
   466→      });
   467→    });
   468→  }
   469→
   470→  /**
   471→   * Validate a single CSV row
   472→   */
   473→  private validateRow(
   474→    row: unknown,
   475→    rowIndex: number
   476→  ): RowValidationResult {
   477→    const parseResult = mileageCsvRowSchema.safeParse(row);
   478→
   479→    if (!parseResult.success) {
   480→      const errorMessages = parseResult.error.errors.map(e => e.message).join(', ');
   481→      return {
   482→        valid: false,
   483→        error: `Row ${rowIndex}: ${errorMessages}`,
   484→      };
   485→    }
   486→
   487→    const data = parseResult.data;
   488→
   489→    // Check for future dates
   490→    const readingDate = new Date(data.reading_date);
   491→    const today = new Date();
   492→    today.setHours(23, 59, 59, 999);
   493→
   494→    if (readingDate > today) {
   495→      return {
   496→        valid: false,
   497→        error: `Row ${rowIndex}: Reading date ${data.reading_date} is in the future`,
   498→        anomaly: {
   499→          trainNumber: data.train_number,
   500→          readingDate: data.reading_date,
   501→          type: 'FUTURE_DATE',
   502→          value: null,
   503→          message: `Reading date ${data.reading_date} is in the future`,
   504→          rawReading: data.odometer_km,
   505→        },
   506→      };
   507→    }
   508→
   509→    return {
   510→      valid: true,
   511→      record: {
   512→        trainNumber: data.train_number,
   513→        readingDate: data.reading_date,
   514→        odometerKm: data.odometer_km,
   515→        rowIndex,
   516→      },
   517→    };
   518→  }
   519→
   520→  /**
   521→   * Process a batch of records within a transaction
   522→   */
   523→  private async processBatch(
   524→    batch: ParsedMileageRecord[],
   525→    fileName: string,
   526→    result: IngestionResult
   527→  ): Promise<{ trainIdsUpdated: Set<string> }> {
   528→    return this.inTransaction('processBatch', async (tx, span) => {
   529→      span.setAttribute('batch.size', batch.length);
   530→
   531→      const trainIdsUpdated = new Set<string>();
   532→
   533→      for (const record of batch) {
   534→        try {
   535→          // Find train
   536→          const train = await tx.query.trains.findFirst({
   537→            where: eq(trains.trainNumber, record.trainNumber),
   538→          });
   539→
   540→          if (!train) {
   541→            result.invalidRecords++;
   542→            const anomaly: AnomalyRecord = {
   543→              trainNumber: record.trainNumber,
   544→              readingDate: record.readingDate,
   545→              type: 'UNKNOWN_TRAIN',
   546→              value: null,
   547→              message: `Train number '${record.trainNumber}' not found in database`,
   548→              rawReading: record.odometerKm,
   549→            };
   550→            result.anomalies.push(anomaly);
   551→            recordIngestionAnomaly('UNKNOWN_TRAIN');
   552→            continue;
   553→          }
   554→
   555→          // Get previous reading
   556→          const previousReading = await tx.query.mileageReadings.findFirst({
   557→            where: and(
   558→              eq(mileageReadings.trainId, train.id),
   559→              sql`${mileageReadings.readingDate} < ${record.readingDate}`
   560→            ),
   561→            orderBy: desc(mileageReadings.readingDate),
   562→          });
   563→
   564→          // Calculate adjusted value (handle meter events)
   565→          const adjustment = await this.getMeterAdjustment(tx, train.id, record.readingDate);
   566→          const adjustedReading = record.odometerKm + adjustment;
   567→
   568→          // Calculate daily km
   569→          let dailyKm: number | null = null;
   570→          let anomalyType: AnomalyType | null = null;
   571→          let anomalyMessage: string | null = null;
   572→
   573→          if (previousReading) {
   574→            dailyKm = adjustedReading - previousReading.adjustedReading;
   575→
   576→            // Anomaly detection
   577→            if (dailyKm < 0) {
   578→              anomalyType = 'NEGATIVE';
   579→              anomalyMessage = `Negative daily mileage: ${dailyKm} km (previous: ${previousReading.adjustedReading}, current: ${adjustedReading})`;
   580→
   581→              result.anomalies.push({
   582→                trainNumber: record.trainNumber,
   583→                readingDate: record.readingDate,
   584→                type: 'NEGATIVE',
   585→                value: dailyKm,
   586→                message: anomalyMessage,
   587→                rawReading: record.odometerKm,
   588→                previousReading: previousReading.adjustedReading,
   589→              });
   590→              recordIngestionAnomaly('NEGATIVE');
   591→            } else if (dailyKm > SPIKE_THRESHOLD_KM) {
   592→              anomalyType = 'SPIKE';
   593→              anomalyMessage = `Unusually high daily mileage: ${dailyKm} km (threshold: ${SPIKE_THRESHOLD_KM})`;
   594→
   595→              result.anomalies.push({
   596→                trainNumber: record.trainNumber,
   597→                readingDate: record.readingDate,
   598→                type: 'SPIKE',
   599→                value: dailyKm,
   600→                message: anomalyMessage,
   601→                rawReading: record.odometerKm,
   602→                previousReading: previousReading.adjustedReading,
   603→              });
   604→              recordIngestionAnomaly('SPIKE');
   605→            }
   606→          }
   607→
   608→          // Insert or update reading
   609→          await tx
   610→            .insert(mileageReadings)
   611→            .values({
   612→              trainId: train.id,
   613→              readingDate: record.readingDate,
   614→              rawReading: record.odometerKm,
   615→              adjustedReading,
   616→              dailyKm,
   617→              validationStatus: anomalyType ? 'ANOMALY' : 'VALID',
   618→              anomalyType: anomalyType ?? undefined,
   619→              anomalyNotes: anomalyMessage ?? undefined,
   620→              sourceFile: fileName,
   621→            })
   622→            .onConflictDoUpdate({
   623→              target: [mileageReadings.trainId, mileageReadings.readingDate],
   624→              set: {
   625→                rawReading: record.odometerKm,
   626→                adjustedReading,
   627→                dailyKm,
   628→                validationStatus: anomalyType ? 'ANOMALY' : 'VALID',
   629→                anomalyType: anomalyType ?? null,
   630→                anomalyNotes: anomalyMessage ?? null,
   631→                sourceFile: fileName,
   632→                ingestedAt: new Date(),
   633→              },
   634→            });
   635→
   636→          result.validRecords++;
   637→          trainIdsUpdated.add(train.id);
   638→        } catch (error) {
   639→          result.invalidRecords++;
   640→          this.log.warn(
   641→            { record, error: error instanceof Error ? error.message : 'Unknown error' },
   642→            'Record processing failed'
   643→          );
   644→        }
   645→      }
   646→
   647→      return { trainIdsUpdated };
   648→    });
   649→  }
   650→
   651→  /**
   652→   * Get cumulative meter adjustment for a train as of a given date
   653→   */
   654→  private async getMeterAdjustment(
   655→    tx: Parameters<Parameters<typeof this.inTransaction>[1]>[0],
   656→    trainId: string,
   657→    asOfDate: string
   658→  ): Promise<number> {
   659→    const events = await tx.query.meterEvents.findMany({
   660→      where: and(
   661→        eq(meterEvents.trainId, trainId),
   662→        lte(meterEvents.eventDate, asOfDate)
   663→      ),
   664→    });
   665→
   666→    return events.reduce((sum, e) => sum + (e.adjustmentKm ?? 0), 0);
   667→  }
   668→
   669→  /**
   670→   * Update train current mileage for all affected trains
   671→   */
   672→  private async updateTrainMileage(
   673→    records: ParsedMileageRecord[],
   674→    trainIds: Set<string>
   675→  ): Promise<void> {
   676→    return this.traced('updateTrainMileage', async (span) => {
   677→      span.setAttribute('trains.count', trainIds.size);
   678→
   679→      // Group records by train, find latest reading
   680→      const latestByTrain = new Map<string, ParsedMileageRecord>();
   681→
   682→      for (const record of records) {
   683→        const existing = latestByTrain.get(record.trainNumber);
   684→        if (!existing || record.readingDate > existing.readingDate) {
   685→          latestByTrain.set(record.trainNumber, record);
   686→        }
   687→      }
   688→
   689→      // Update train current_mileage for each affected train
   690→      for (const [trainNumber, record] of latestByTrain) {
   691→        await this.db
   692→          .update(trains)
   693→          .set({
   694→            currentMileageKm: record.odometerKm,
   695→            updatedAt: new Date(),
   696→          })
   697→          .where(eq(trains.trainNumber, trainNumber));
   698→      }
   699→
   700→      // Update fleet mileage targets
   701→      await this.db.execute(sql`SELECT update_fleet_mileage_targets()`);
   702→
   703→      this.log.info(
   704→        { trainsUpdated: latestByTrain.size },
   705→        'Train mileages updated'
   706→      );
   707→    });
   708→  }
   709→
   710→  // ===========================================================================
   711→  // Meter Event Management
   712→  // ===========================================================================
   713→
   714→  /**
   715→   * Create a meter event (for manual corrections or detected resets)
   716→   */
   717→  async createMeterEvent(
   718→    trainId: string,
   719→    eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP',
   720→    eventDate: string,
   721→    oldReading: number,
   722→    newReading: number,
   723→    reason?: string,
   724→    createdBy?: string
   725→  ): Promise<MeterEventRecord> {
   726→    return this.inTransaction('createMeterEvent', async (tx, span) => {
   727→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   728→      span.setAttribute('event.type', eventType);
   729→
   730→      // Verify train exists
   731→      const train = await tx.query.trains.findFirst({
   732→        where: eq(trains.id, trainId),
   733→      });
   734→
   735→      if (!train) {
   736→        throw new BusinessRuleError(`Train not found: ${trainId}`, {
   737→          rule: 'train_exists',
   738→          context: { trainId },
   739→        });
   740→      }
   741→
   742→      // Calculate adjustment (cumulative offset to maintain mileage continuity)
   743→      const adjustmentKm = oldReading - newReading;
   744→
   745→      // Insert meter event
   746→      const [event] = await tx
   747→        .insert(meterEvents)
   748→        .values({
   749→          trainId,
   750→          eventDate,
   751→          eventType,
   752→          oldMeterReading: oldReading,
   753→          newMeterReading: newReading,
   754→          adjustmentKm,
   755→          reason,
   756→          createdBy,
   757→        })
   758→        .returning();
   759→
   760→      this.log.info(
   761→        {
   762→          eventId: event.id,
   763→          trainId,
   764→          trainNumber: train.trainNumber,
   765→          eventType,
   766→          oldReading,
   767→          newReading,
   768→          adjustmentKm,
   769→        },
   770→        'Meter event created'
   771→      );
   772→
   773→      return {
   774→        trainNumber: train.trainNumber,
   775→        trainId,
   776→        eventDate,
   777→        eventType,
   778→        oldReading,
   779→        newReading,
   780→        adjustmentKm,
   781→      };
   782→    });
   783→  }
   784→
   785→  /**
   786→   * Get meter events for a train
   787→   */
   788→  async getMeterEvents(trainId: string): Promise<MeterEventRecord[]> {
   789→    return this.traced('getMeterEvents', async (span) => {
   790→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   791→
   792→      const train = await this.db.query.trains.findFirst({
   793→        where: eq(trains.id, trainId),
   794→      });
   795→
   796→      if (!train) {
   797→        throw new BusinessRuleError(`Train not found: ${trainId}`, {
   798→          rule: 'train_exists',
   799→          context: { trainId },
   800→        });
   801→      }
   802→
   803→      const events = await this.db.query.meterEvents.findMany({
   804→        where: eq(meterEvents.trainId, trainId),
   805→        orderBy: desc(meterEvents.eventDate),
   806→      });
   807→
   808→      return events.map((e) => ({
   809→        trainNumber: train.trainNumber,
   810→        trainId: e.trainId,
   811→        eventDate: e.eventDate,
   812→        eventType: e.eventType as 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP',
   813→        oldReading: e.oldMeterReading ?? 0,
   814→        newReading: e.newMeterReading ?? 0,
   815→        adjustmentKm: e.adjustmentKm ?? 0,
   816→      }));
   817→    });
   818→  }
   819→
   820→  // ===========================================================================
   821→  // Health Monitoring
   822→  // ===========================================================================
   823→
   824→  /**
   825→   * Check file arrival health
   826→   *
   827→   * Returns whether files have been received within the expected timeframe.
   828→   * Used by health check endpoints and alerting.
   829→   */
   830→  async checkFileArrivalHealth(): Promise<{
   831→    healthy: boolean;
   832→    lastFileAt: Date | null;
   833→    hoursSinceLastFile: number | null;
   834→    alertThresholdHours: number;
   835→  }> {
   836→    const alertThresholdHours = ALERT_THRESHOLD_HOURS;
   837→
   838→    if (!this.lastFileReceivedAt) {
   839→      return {
   840→        healthy: true, // No baseline yet
   841→        lastFileAt: null,
   842→        hoursSinceLastFile: null,
   843→        alertThresholdHours,
   844→      };
   845→    }
   846→
   847→    const hoursSinceLastFile =
   848→      (Date.now() - this.lastFileReceivedAt.getTime()) / (1000 * 60 * 60);
   849→
   850→    const healthy = hoursSinceLastFile <= alertThresholdHours;
   851→
   852→    return {
   853→      healthy,
   854→      lastFileAt: this.lastFileReceivedAt,
   855→      hoursSinceLastFile: Math.round(hoursSinceLastFile * 10) / 10,
   856→      alertThresholdHours,
   857→    };
   858→  }
   859→
   860→  /**
   861→   * Get ingestion statistics
   862→   */
   863→  async getIngestionStats(days: number = 7): Promise<{
   864→    totalFiles: number;
   865→    totalRecords: number;
   866→    totalAnomalies: number;
   867→    anomaliesByType: Record<string, number>;
   868→    averageRecordsPerFile: number;
   869→  }> {
   870→    return this.traced('getIngestionStats', async (span) => {
   871→      span.setAttribute('stats.days', days);
   872→
   873→      const since = new Date();
   874→      since.setDate(since.getDate() - days);
   875→
   876→      // Get anomaly counts by type
   877→      const anomalyStats = await this.db
   878→        .select({
   879→          anomalyType: mileageReadings.anomalyType,
   880→          count: sql<number>`count(*)::int`,
   881→        })
   882→        .from(mileageReadings)
   883→        .where(
   884→          and(
   885→            eq(mileageReadings.validationStatus, 'ANOMALY'),
   886→            sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`
   887→          )
   888→        )
   889→        .groupBy(mileageReadings.anomalyType);
   890→
   891→      const anomaliesByType: Record<string, number> = {};
   892→      let totalAnomalies = 0;
   893→
   894→      for (const stat of anomalyStats) {
   895→        const type = stat.anomalyType ?? 'UNKNOWN';
   896→        anomaliesByType[type] = stat.count;
   897→        totalAnomalies += stat.count;
   898→      }
   899→
   900→      // Get total records count
   901→      const [recordStats] = await this.db
   902→        .select({
   903→          total: sql<number>`count(*)::int`,
   904→          files: sql<number>`count(distinct ${mileageReadings.sourceFile})::int`,
   905→        })
   906→        .from(mileageReadings)
   907→        .where(sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`);
   908→
   909→      const totalRecords = recordStats?.total ?? 0;
   910→      const totalFiles = recordStats?.files ?? 0;
   911→
   912→      return {
   913→        totalFiles,
   914→        totalRecords,
   915→        totalAnomalies,
   916→        anomaliesByType,
   917→        averageRecordsPerFile: totalFiles > 0 ? Math.round(totalRecords / totalFiles) : 0,
   918→      };
   919→    });
   920→  }
   921→
   922→  // ===========================================================================
   923→  // Utility Methods
   924→  // ===========================================================================
   925→
   926→  /**
   927→   * Split array into chunks
   928→   */
   929→  private chunk<T>(array: T[], size: number): T[][] {
   930→    const chunks: T[][] = [];
   931→    for (let i = 0; i < array.length; i += size) {
   932→      chunks.push(array.slice(i, i + size));
   933→    }
   934→    return chunks;
   935→  }
   936→}
   937→
   938→// =============================================================================
   939→// Singleton Export
   940→// =============================================================================
   941→
   942→let ingestionServiceInstance: IngestionService | null = null;
   943→
   944→export function getIngestionService(): IngestionService {
   945→  if (!ingestionServiceInstance) {
   946→    ingestionServiceInstance = new IngestionService();
   947→  }
   948→  return ingestionServiceInstance;
   949→}
   950→
   951→export default IngestionService;
   952→

